@import '../../utils/interaction-fill.css';
@import '../../utils/control-inactive.css';
@import '../../utils/control-density.css';
@import '../../utils/control-width.css';
@import '../../utils/typography.css';

:host(.input-host) {
  display: inline-flex;
  flex-direction: column;
  gap: var(--dimension-space-050);
  --ds-input-fg: var(--color-foreground-primary);
  --ds-input-placeholder: var(--color-foreground-secondary);
  --ds-input-placeholder-active: var(--color-foreground-quaternary);
  --ds-input-adornment-fg: var(--color-foreground-secondary);
  --ds-input-border: var(--color-border-secondary);
}

:host(.ds-control-width--fill),
:host(.ds-control-width--fill) .input-control {
  width: 100%;
}

.input-control {
  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  height: var(--ds-control-height, var(--dimension-size-400));
  padding: 0 var(--ds-control-padding-inline, var(--dimension-space-075));
  gap: var(--ds-control-gap, var(--dimension-space-050));
  overflow: hidden;
  background: transparent;
  border: none;
  border-radius: var(--ds-control-radius, var(--dimension-radius-025));
  color: var(--ds-input-fg);
}

.input-control--bordered {
  --ds-interaction-border-width: var(--dimension-stroke-width-012);
  --ds-interaction-border-color: var(--ds-input-border);
}

.input-control--error {
  --ds-interaction-border-width: var(--dimension-stroke-width-018);
  --ds-interaction-border-color: var(--color-border-bold-negative);
}

.input-control:focus-within:not(.input-control--error) {
  --ds-interaction-border-width: var(--dimension-stroke-width-018);
  --ds-interaction-border-color: var(--color-border-bold-brand);
}

:host(.ds-control-inactive) .input-control::after {
  background: transparent;
}

.native-input {
  position: relative;
  z-index: 2;
  flex: 1 1 auto;
  min-width: 0;
  height: 100%;
  padding: 0 var(--ds-control-label-inset, var(--dimension-space-025));
  background: transparent;
  border: none;
  border-radius: inherit;
  outline: none;
  color: var(--ds-input-fg);
  font-family: inherit;
  -webkit-appearance: none;
  appearance: none;
}

.native-input:disabled {
  cursor: not-allowed;
}

.native-input:read-only:not(:disabled) {
  cursor: default;
}

.native-input::placeholder {
  color: var(--ds-input-placeholder);
}

.native-input:focus::placeholder {
  color: var(--ds-input-placeholder-active);
}

.native-input[type='search']::-webkit-search-cancel-button,
.native-input[type='search']::-webkit-search-decoration {
  display: none;
}

.input-control__prefix,
.input-control__suffix {
  position: relative;
  z-index: 2;
  flex-shrink: 0;
  width: var(--ds-control-icon, var(--dimension-iconography-md));
  height: var(--ds-control-icon, var(--dimension-iconography-md));
  display: inline-flex;
  align-items: center;
  justify-content: center;
  color: var(--ds-input-adornment-fg);
}

.input-control__suffix--empty {
  display: none;
}

.input-control__clear {
  position: relative;
  z-index: 2;
  flex-shrink: 0;
  align-self: center;
}

.input-control.ds-control--md:has(.input-control__clear),
.input-control.ds-control--sm:has(.input-control__clear) {
  padding-right: var(--dimension-space-050);
}

.input-control.ds-control--xs:has(.input-control__clear) {
  padding-right: 0;
}

.error-text {
  width: 100%;
}

import { AttachInternals, Component, Prop, State, Event, EventEmitter, Element, Method, Watch, h, Host } from '@stencil/core';
import { controlWidthClass, CONTROL_TEXT_VARIANT, type ControlWidth } from '../../utils';

export type InputType = 'text' | 'email' | 'tel' | 'url' | 'search' | 'password';
export type InputSize = 'md' | 'sm' | 'xs';
export type InputWidth = ControlWidth;

const ICON_SIZE: Record<InputSize, 'md' | 'sm' | 'xs'> = {
  md: 'md',
  sm: 'sm',
  xs: 'xs',
};

const CLEAR_BUTTON_SIZE: Record<InputSize, 'sm' | 'xs'> = {
  md: 'sm',
  sm: 'xs',
  xs: 'xs',
};

let idCounter = 0;

@Component({
  tag: 'ds-input',
  styleUrl: 'Input.css',
  scoped: true,
  formAssociated: true,
})
export class Input {
  @Element() el!: HTMLElement;
  @AttachInternals() internals!: ElementInternals;

  private generatedId = `ds-input-${++idCounter}`;
  private errorId = `${this.generatedId}-error`;

  @Prop({ mutable: true }) value: string = '';
  @Prop({ reflect: true }) name: string | undefined;
  @Prop({ reflect: true }) form: string | undefined;
  @Prop({ reflect: true }) disabled: boolean = false;
  /** Keeps the value focusable and submittable while preventing edits. */
  @Prop({ reflect: true }) readOnly: boolean = false;
  @Prop({ reflect: true }) required: boolean = false;
  @Prop() requiredMessage: string = 'This field is required.';
  @Prop() clearLabel: string = 'Clear';
  @Prop() placeholder: string | undefined;
  @Prop() type: InputType = 'text';
  /** Native browser autofill hint. */
  @Prop({ attribute: 'autocomplete' }) autoComplete: string | undefined;
  /** Preferred virtual keyboard without changing the value semantics. */
  @Prop({ attribute: 'inputmode' }) inputMode: string = '';
  /** Preferred virtual-keyboard action label. */
  @Prop({ attribute: 'enterkeyhint' }) enterKeyHint: string = '';
  /** Control density. */
  @Prop() size: InputSize = 'md';
  /** Width fit — fill the parent (default) or hug the available content. */
  @Prop() width: InputWidth = 'fill';
  /** Show the standard inset border. */
  @Prop() hasBorder: boolean = true;
  /** Optional leading icon name. */
  @Prop() icon: string | undefined;
  @Prop() isInactive: boolean = false;
  @Prop() autoFocus: boolean = false;
  @Prop() error: boolean = false;
  @Prop() errorMessage: string | undefined;
  /** Associates the internal input with an external <label>. */
  @Prop() inputId: string | undefined;
  @Prop({ attribute: 'aria-label' }) ariaLabel: string | null = null;
  @Prop({ attribute: 'aria-labelledby' }) ariaLabelledby: string | undefined;
  @Prop({ attribute: 'aria-describedby' }) ariaDescribedby: string | undefined;

  @Event() dsChange!: EventEmitter<string>;
  @Event() dsClear!: EventEmitter<void>;

  private initialValue = '';
  @State() private formDisabled = false;
  @State() private hasSuffix = false;
  @State() private focused = false;
  @State() private touched = false;

  componentWillLoad() {
    this.initialValue = this.value;
    this.hasSuffix = Boolean(this.el.querySelector('[slot="suffix"]'));
    this.syncFormValue();
  }

  componentDidRender() {
    const hasSuffix = Boolean(this.el.querySelector('[slot="suffix"]'));
    if (hasSuffix !== this.hasSuffix) this.hasSuffix = hasSuffix;
  }

  @Watch('value')
  @Watch('disabled')
  @Watch('isInactive')
  @Watch('required')
  syncFormValue() {
    const inactive = this.isInactive || this.disabled || this.formDisabled;
    this.internals.setFormValue(inactive ? null : this.value);
    const missing = this.required && !inactive && this.value.length === 0;
    this.internals.setValidity(missing ? { valueMissing: true } : {}, missing ? this.requiredMessage : '');
  }

  formDisabledCallback(disabled: boolean) {
    this.formDisabled = disabled;
    this.syncFormValue();
  }

  formResetCallback() {
    this.value = this.initialValue;
  }

  formStateRestoreCallback(state: string | File | FormData | null) {
    this.value = typeof state === 'string' ? state : '';
  }

  @Method()
  async setFocus() {
    this.el.querySelector('input')?.focus();
  }

  private handleInput = (e: Event) => {
    this.value = (e.target as HTMLInputElement).value;
    this.dsChange.emit(this.value);
  };

  private handleFocus = () => {
    this.focused = true;
  };

  private handleBlur = () => {
    this.focused = false;
    this.touched = true;
  };

  private handleClear = () => {
    this.value = '';
    this.dsChange.emit('');
    this.dsClear.emit();
    this.el.querySelector('input')?.focus();
  };

  render() {
    const inputId = this.inputId ?? this.generatedId;
    const inactive = this.isInactive || this.disabled || this.formDisabled;
    const filled = this.value.length > 0;
    const dirty = this.value !== this.initialValue;
    const showClear = this.type === 'search' && filled && !inactive && !this.readOnly;
    const showError = this.error && Boolean(this.errorMessage);
    const textVariant = CONTROL_TEXT_VARIANT[this.size];
    const iconSize = ICON_SIZE[this.size];

    const describedBy = [
      this.ariaDescribedby,
      showError ? this.errorId : undefined,
    ].filter(Boolean).join(' ') || undefined;

    return (
      <Host
        class={{
          'input-host': true,
          'ds-control-inactive': inactive,
          [`ds-control--${this.size}`]: true,
          ...controlWidthClass(this.width),
        }}
        data-disabled={inactive ? '' : undefined}
        data-readonly={this.readOnly ? '' : undefined}
        data-required={this.required ? '' : undefined}
        data-invalid={this.error ? '' : undefined}
        data-filled={filled ? '' : undefined}
        data-focused={this.focused ? '' : undefined}
        data-dirty={dirty ? '' : undefined}
        data-touched={this.touched ? '' : undefined}
      >
        <div
          class={{
            'input-control': true,
            'input-control--bordered': this.hasBorder || this.error,
            'input-control--error': this.error,
            'ds-interaction-fill': true,
            [`ds-control--${this.size}`]: true,
          }}
        >
          {this.icon && (
            <span class="input-control__prefix ds-interaction-fill__content" aria-hidden="true">
              <ds-icon name={this.icon} size={iconSize} color="inherit" />
            </span>
          )}
          <input
            type={this.type}
            id={inputId}
            value={this.value}
            placeholder={this.placeholder}
            disabled={inactive}
            readOnly={this.readOnly}
            required={this.required}
            autoFocus={this.autoFocus}
            autoComplete={this.autoComplete}
            inputMode={this.inputMode || undefined}
            enterKeyHint={this.enterKeyHint || undefined}
            class={`native-input ds-text--${textVariant.replace('text-', '')} ds-text--regular ds-interaction-fill__content`}
            aria-label={this.ariaLabel}
            aria-labelledby={this.ariaLabelledby}
            aria-describedby={describedBy}
            aria-invalid={this.error ? 'true' : undefined}
            onInput={this.handleInput}
            onFocus={this.handleFocus}
            onBlur={this.handleBlur}
          />
          <span class={{ 'input-control__suffix': true, 'input-control__suffix--empty': !this.hasSuffix }}>
            <slot name="suffix" />
          </span>
          {showClear && (
            <ds-button-unfilled
              class="input-control__clear"
              variant="icon"
              size={CLEAR_BUTTON_SIZE[this.size]}
              icon="CrossCircle"
              hasBorder={false}
              rounded
              ariaLabel={this.clearLabel}
              onDsClick={this.handleClear}
            />
          )}
        </div>
        {showError && (
          <ds-text
            class="error-text"
            as="div"
            variant="text-body-small"
            color="negative"
            textId={this.errorId}
            role="alert"
          >
            {this.errorMessage}
          </ds-text>
        )}
      </Host>
    );
  }
}
